import{c as n,a7 as r,y as p,B as t,v as a,D as e}from"./chunks/framework.3cjvm90C.js";const R=JSON.parse('{"title":"OpenR：增强大语言模型推理能力的开源框架","description":"介绍OpenR开源框架如何通过搜索与推理增强大语言模型的推理能力","frontmatter":{"title":"OpenR：增强大语言模型推理能力的开源框架","description":"介绍OpenR开源框架如何通过搜索与推理增强大语言模型的推理能力"},"headers":[],"relativePath":"rlhf/infra/openr.md","filePath":"rlhf/infra/openr.md","lastUpdated":1782448598000}'),M={name:"rlhf/infra/openr.md"};function h(s,l,o,m,i,L){return r(),p("div",null,[...l[0]||(l[0]=[t("",36),a("p",null,[e("我们遵循 OmegaPRM [Luo 等人， 2024] 并通过使用 LLMs 构建状态-动作树来收集 PRM 训练示例。对于每个问题，构建一棵树，其中每个节点包含问题 $q$、解决方案前缀 $s$ 和所有先前的 rollout ${(s,r_{i})}"),a("em",{i:""},"{i=1}^{k}$（$r"),e("$ 表示第 $i$ 个 rollout）。每条边表示从节点开始的单个步骤或一系列步骤。对于每个节点，我们计算蒙特卡罗估计 $MC(s)$ 和价值函数 $Q(s,r)$ 以指导在树遍历期间选择 rollout。价值函数定义为：$Q(s,r)=\\alpha\\cdot\\frac{1}{1-MC(s)}\\cdot\\beta\\cdot\\frac{\\text{len}(r)}{1-\\alpha}$，其中 $\\alpha$、$\\beta$ 和 $L$ 是常数，$\\text{len}(r)$ 是 rollout 的长度。我们还计算探索项：$U(s)=c_{\\text{puct} }\\cdot\\frac{\\sqrt{\\sum_{i}N(s_{i})} }{1+N(s)}$，其中 $N(s)$ 是访问计数，$c_{\\text{puct} }$ 是鼓励探索的常数。在选择阶段，使用 PUCT 算法的变体选择 rollout：$(s,r)=\\arg\\max_{(s,r)}[Q(s,r)+U(s)]$。这种启发式方法选择最有价值的 rollout。然后使用二分搜索识别所选 rollout 中的第一个错误，并将 $0<MC(s)$ 的 rollout 添加到候选池中。所有在第一个错误之前的位置成为进一步探索的新状态。")],-1),t("",5),a("p",null,[e("我们将数学问题转化为语言增强的马尔可夫决策过程（MDP） $\\mathcal{M}=(\\mathcal{V},\\mathcal{S},\\mathcal{A},\\mathcal{T},R,\\gamma)$(Van Otterlo 和 Wiering， 2012； Carta 等人， 2023)。给定 $\\mathcal{V}$ 词汇表和 $w\\in\\mathcal{V}$ 标记，$\\mathcal{A}\\subset\\mathcal{V}^{N}$，$\\mathcal{S}\\subset\\mathcal{V}^{N}$ 分别是动作和状态空间，即动作和状态是标记序列。$\\mathcal{T}:\\mathcal{S}\\times\\mathcal{A}\\mapsto\\mathcal{S}$ 是状态转移函数。$R:\\mathcal{S}\\times\\mathcal{A}\\mapsto\\mathbb{R}$ 是响应每个动作的奖励函数，$\\gamma$ 是通常小于 1 的折扣因子。初始状态 $s_{0}$ 表示数学问题解决场景中的给定问题。语言模型接收此输入并生成一个中间推理步骤，表示为动作 $a_{0}$。然后，此动作 $a_{0}$ 与初始问题 $s_{0}$ 连接以形成后续状态 $s_{1}$，用于推断下一个动作 $a_{1}$，此迭代过程继续，每个状态-动作对依次通知下一个状态，即 $\\mathcal{T}😒_{t+1}={s_{t},a_{t}}$ 在时间步 $t$，直到模型得出最终答案。在推断每个动作 $a_{t}$ 后，模型从训练良好的 PRM 接收奖励信号 $r^{PRM}"),a("em",{t:""},"{t}=R(s"),e(",a_{t})$。遵循此过程，轨迹的最大时间步为 $T$，代理获得折扣累积回报 $R^{\\gamma}=\\sum_{t=0}^{T}\\gamma^{t}r^{PRM}_{t}$， RL 算法的目标是最大化此回报。我们相应地实现此 MDP 作为强化学习环境，如 OpenAI 的 Gym。在这些环境中，数学问题被呈现为任务，模型采取顺序动作来解决问题，对正确动作给予奖励，对错误动作给予惩罚，从而使模型能够通过试错迭代学习和完善其问题解决策略，最终增强其数学推理技能。")],-1),a("p",null,[e("RL 训练。使用强化学习训练 LLMs 通常涉及近端策略优化（PPO）(Schulman 等人， 2017)，以使生成的语言输出与期望的动作对齐。这种方法通过强化生成既上下文准确又与预定义目标一致的响应，有效地将语言理解与战略规划联系起来。我们提供传统的 PPO 和 PPO 的高效变体，即组相对策略优化（GRPO）(Shao 等人， 2024)。这两者之间的主要区别在于它们对优势值估计的方法。具体来说， PPO 利用网络来近似状态价值函数，利用广义优势估计（GAE）技术 (Schulman 等人， 2015) 来推导优势。相比之下， GRPO 通过直接使用归一化的奖励信号来估计动作的优势，即 $A(s_{t},a_{t})=\\frac{r^{PRM}"),a("em",{t:""},"{t}-\\text{mean}(r^{PRM}"),e(")}{\\text{std}(r^{PRM})}$。与 PPO 相比， GRPO 绕过了额外批评网络的需求，并减少了训练期间消耗的资源，然而，它更强调 PRM 的稳定性。")],-1),a("h3",{id:"解码-推理时间引导搜索和规划",tabindex:"-1"},[e("解码：推理时间引导搜索和规划 "),a("a",{class:"header-anchor",href:"#解码-推理时间引导搜索和规划","aria-label":"Permalink to “解码：推理时间引导搜索和规划”"},"​")],-1),a("p",null,"遵循 Snell 等人 [2024]，我们使用 PRM 评估每个解决方案步骤的准确性。一旦训练出高质量的过程奖励模型，我们将其与语言模型集成到解码过程中，实现引导搜索和跨多个生成的评分或投票。",-1),a("p",null,[e("为了使用 PRM 作为验证器，我们定义了一种评估 LLM 生成解决方案正确性的方法。具体来说，我们将单个步骤的分数 ${r^{PRM}"),a("em",{t:"0"},"{t}}"),e("^{T}$ 映射到最终分数。遵循 Lightman 等人 [2023] 和 Snell 等人 [2024] 概述的策略，我们采用两种方法：")],-1),a("ul",null,[a("li",null,[a("p",null,[e("*"),a("em",null,"PRM-Min"),e("：选择所有分数中的最小值，即 $v=\\min{r^{PRM}"),a("em",{t:"0"},"{t}}"),e("^{T}$。")])]),a("li",null,[a("p",null,[e("*"),a("em",null,"PRM-Last"),e("：选择最后一步的分数作为最终分数，即 $v=r^{PRM}_{T}$。在 Snell 等人 [2024] 中，这种策略与_PR")])]),a("li",null,[a("p",null,"M-Min_ 表现相当。"),a("p",null,"一旦通过扩展测试时计算生成多个答案，我们需要根据它们的分数选择最佳答案的策略。我们采用了 Feng 等人 [2024] 的三种策略："),a("ul",null,[a("li",null,[a("strong",null,[a("em",null,"多数投票")]),e("：使用多数投票聚合答案：")])])])],-1),t("",31)])])}const P=n(M,[["render",h]]);export{R as __pageData,P as default};
